const input = $('Apply Article Classification Proposal Webhook').first().json;
const proposal = input.body?.proposal ?? input.body ?? input.proposal ?? input;
const now = new Date().toISOString();
const articleTypes = new Set(['news_article', 'official_announcement', 'press_release', 'video_or_stream', 'social_post', 'guide_or_database', 'image_gallery', 'other']);
const categories = new Set(['talent_activity', 'live_or_music', 'event', 'product_or_goods', 'collaboration', 'audition_or_recruitment', 'company_or_business', 'game_or_technology', 'media_or_editorial', 'community_or_fan', 'other']);
const relevanceLevels = new Set(['in_scope', 'low_relevance', 'out_of_scope']);
const methods = new Set(['ai_review', 'manual_review']);
const existingArticles = $input.all().map((item) => item.json);
const articleKeyByUrl = new Map(existingArticles
  .map((article) => [String(article.url ?? "").trim(), String(article.article_key ?? "").trim()])
  .filter(([url, articleKey]) => url && articleKey)
);
const existingArticleKeys = new Set(articleKeyByUrl.values());
function text(value, field, required = true) {
  const result = String(value ?? '').trim();
  if (required && !result) throw new Error(`${field} is required.`);
  return result;
}
function list(value, field) {
  if (!Array.isArray(value)) throw new Error(`${field} must be an array.`);
  return value;
}
function categoryList(value) {
  const parsed = Array.isArray(value) ? value : JSON.parse(String(value ?? '[]'));
  if (!Array.isArray(parsed)) throw new Error('secondary_categories_json must be an array.');
  const values = parsed.map((item) => text(item, 'secondary_categories_json item'));
  if (values.length > 3) throw new Error('secondary_categories_json may contain at most 3 values.');
  if (new Set(values).size !== values.length) throw new Error('secondary_categories_json contains duplicates.');
  for (const value of values) if (!categories.has(value)) throw new Error(`Invalid secondary category: ${value}`);
  return values;
}
if (Number(proposal.proposalVersion ?? 1) !== 1) throw new Error('proposalVersion must be 1.');
const rows = list(proposal.classifications, 'classifications');
if (!rows.length) throw new Error('classifications must contain at least one row.');
const seen = new Set();
const classifications = rows.map((row) => {
  const requestedArticleKey = text(row.article_key, "classifications.article_key", false);
  const articleUrl = text(row.article_url, "classifications.article_url", false);
  const articleKey = requestedArticleKey || articleKeyByUrl.get(articleUrl) || "";
  if (!articleKey) throw new Error("Each classification requires a known article_url or article_key.");
  if (requestedArticleKey && !existingArticleKeys.has(requestedArticleKey)) {
    throw new Error("Unknown article_key: " + requestedArticleKey);
  }
  if (articleUrl && articleKeyByUrl.has(articleUrl) && articleKeyByUrl.get(articleUrl) !== articleKey) {
    throw new Error("article_url does not match article_key: " + articleUrl);
  }
  if (seen.has(articleKey)) throw new Error("classifications contains a duplicate article: " + articleKey);
  seen.add(articleKey);
  const articleType = text(row.article_type, 'classifications.article_type');
  const primaryCategory = text(row.primary_category, 'classifications.primary_category');
  const secondary = categoryList(row.secondary_categories_json);
  const relevance = text(row.relevance, 'classifications.relevance');
  const confidence = Number(row.confidence);
  const method = text(row.classification_method ?? 'ai_review', 'classifications.classification_method');
  if (!articleTypes.has(articleType)) throw new Error(`Invalid article_type: ${articleType}`);
  if (!categories.has(primaryCategory)) throw new Error(`Invalid primary_category: ${primaryCategory}`);
  if (secondary.includes(primaryCategory)) throw new Error('primary_category must not be included in secondary_categories_json.');
  if (!relevanceLevels.has(relevance)) throw new Error(`Invalid relevance: ${relevance}`);
  if (!Number.isFinite(confidence) || confidence < 0 || confidence > 1) throw new Error('confidence must be between 0 and 1.');
  if (!methods.has(method)) throw new Error(`Invalid classification_method: ${method}`);
  return {
    article_key: articleKey,
    article_type: articleType,
    primary_category: primaryCategory,
    secondary_categories_json: JSON.stringify(secondary),
    relevance,
    confidence,
    evidence_text: text(row.evidence_text, 'classifications.evidence_text').slice(0, 2000),
    classification_method: method,
    classified_at: text(row.classified_at, 'classifications.classified_at', false) || now
  };
});
return [{ json: { proposalDate: text(proposal.proposalDate ?? now.slice(0, 10), 'proposalDate'), classifications, counts: { classifications: classifications.length } } }];
